#!/usr/bin/env python3
"""Emit canonical verify.sh from base64. Run from repo root: python3 scripts/selfheal/emit_verify_sh.py"""
import base64
import os
REPO_ROOT = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
OUT = os.path.join(REPO_ROOT, "scripts", "selfheal", "verify.sh")
B64 = """"""
with open(OUT, "wb") as f:
    f.write(base64.b64decode(B64))
os.chmod(OUT, 0o755)
print("Wrote", OUT)
